try:
    log_dir.mkdir(parents=True, exist_ok=True)
except OSError as e:
    raise RuntimeError(f"Failed to create log directory: {log_dir}. Error: {e}") from e

def exception(self, message: str, **kwargs):
    extra_info = " | ".join(f"{k}={v}" for k, v in kwargs.items()) if kwargs else ""
    full_message = f"{message} {extra_info}".strip()
    try:
        raise  # Re-raise the last exception to get the traceback
    except Exception as e:
        # Log only the exception type and message
        self.logger.error(f"{full_message}: {type(e).__name__}: {str(e)}")
